class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        int n = nums1.size();
        vector<int> diff;
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            int d = abs(nums1[i] - nums2[i]);
            diff.push_back(d);
            sum += (long long)d * d;
        }
        sort(diff.rbegin(), diff.rend());
        for (int i = 0; i < n; i++) {
            int reduce = min(k1 + k2, diff[i] / 2);
            if (reduce > 0) {
                sum -= (long long)(2 * reduce - 1) * reduce;
                k1 -= reduce;
                k2 -= reduce;
                if (k1 < 0) {
                    reduce += k1;
                    k1 = 0;
                }
                if (k2 < 0) {
                    reduce += k2;
                    k2 = 0;
                }
            }
        }
        return sum;
    }
};
